### Complete Peer Example

```javascript
const peer = new ZYNQ.Peer({
  video: true,
  audio: true,
  txt: true,
  autoReconnect: true
})

peer.on("ready", id => console.log("My ID:", id))

peer.on("message", msg => {
  console.log(`From ${msg.from}:`, msg.data)
})

peer.on("stream", ({ from, stream }) => {
  remoteVideo.srcObject = stream
})

peer.on("open", peerId => console.log("Connected to", peerId))

// Connect & send
document.getElementById("connectBtn").onclick = () => {
  peer.connect("friend-peer-id")
}

// Send message
peer.send("friend-peer-id", "Hello from ZYNQ! 👋")

// Start call
peer.call("friend-peer-id")
```
